'use client';

import React, { createContext, useContext, useMemo } from 'react';
import { useAuth } from './AuthContext';
import { darken, lighten, contrastText } from '../utils/colorUtils';

interface Colors {
  primary: string;
  primaryDark: string;
  primaryLight: string;
  primaryFaded: string;
  secondary: string;
  accent: string;
  background: string;
  surface: string;
  text: string;
  textSecondary: string;
  textMuted: string;
  success: string;
  error: string;
  warning: string;
  border: string;
  borderLight: string;
  headerText: string;
}

interface ThemeContextType {
  themeId: string;
  colors: Colors;
  logoUrl: string | null;
  empresaNombre: string | null;
  loading: boolean;
}

const DEFAULT_COLORS: Colors = {
  primary: '#2980b9',
  primaryDark: '#1e6a9e',
  primaryLight: '#5ca0d3',
  primaryFaded: '#e0f0ff',
  secondary: '#00d2ff',
  accent: '#00d2ff',
  background: '#fafafa',
  surface: '#ffffff',
  text: '#3D3D3D',
  textSecondary: '#666666',
  textMuted: '#999999',
  success: '#7DB88F',
  error: '#D4726A',
  warning: '#D4A574',
  border: '#E8E4E0',
  borderLight: '#F2EFEB',
  headerText: '#1a1a1a',
};

const ThemeContext = createContext<ThemeContextType>({
  themeId: 'default',
  colors: DEFAULT_COLORS,
  logoUrl: null,
  empresaNombre: null,
  loading: false,
});

export const ThemeProvider = ({ children }: { children: React.ReactNode }) => {
  const { profile, loading: authLoading } = useAuth();

  const value = useMemo<ThemeContextType>(() => {
    if (authLoading) {
      return { themeId: 'loading', colors: DEFAULT_COLORS, logoUrl: null, empresaNombre: null, loading: true };
    }

    if (!profile || !profile.empresaId) {
      return { themeId: 'default', colors: DEFAULT_COLORS, logoUrl: null, empresaNombre: null, loading: false };
    }

    const primary = (profile.colorPrimario || DEFAULT_COLORS.primary).trim();
    const secondary = (profile.colorSecundario || DEFAULT_COLORS.secondary).trim();
    const background = (profile.colorBackground || DEFAULT_COLORS.background).trim();

    const colors: Colors = {
      ...DEFAULT_COLORS,
      primary,
      primaryDark: darken(primary, 0.15),
      primaryLight: lighten(primary, 0.25),
      primaryFaded: lighten(primary, 0.85),
      secondary,
      accent: secondary,
      background,
      headerText: contrastText(secondary),
    };

    return {
      themeId: `empresa-${profile.empresaId}`,
      colors,
      logoUrl: profile.logoUrl || null,
      empresaNombre: profile.empresaNombre || null,
      loading: false,
    };
  }, [profile, authLoading]);

  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) throw new Error('useTheme debe usarse dentro de ThemeProvider');
  return context;
};

export default ThemeContext;
